// TemporadaManager.js
import { generarPlayoffsParaLiga } from "../generation/PlayoffManager";
import { useNavigate } from "react-router-dom";

export function todasLasJornadasJugadas(clasificacion) {
    for (const liga in clasificacion) {
        const equipos = clasificacion[liga];
        const numEquipos = equipos.length;

        // Cada equipo debe haber jugado (numEquipos - 1) * 2 partidos (ida y vuelta)
        const esperados = (numEquipos - 1) * 2;

        for (const equipo of equipos) {
            if (equipo.partidosJugados < esperados) return false;
        }
    }
    return true;
}

export function verificarFinTemporadaYLanzarPlayoffs() {
    const calendario = JSON.parse(localStorage.getItem("calendario")) || {};
    const clasificacion = JSON.parse(localStorage.getItem("clasificacion")) || {};
    const playoffsInfo = JSON.parse(localStorage.getItem("playoffs")) || {};

    if (!todasLasJornadasJugadas(clasificacion)) return;

    const rondas = [];
    const ligasConPlayoff = Object.entries(playoffsInfo)
        .filter(([liga, num]) => num > 0)
        .map(([liga]) => liga);

    for (let liga of ligasConPlayoff) {
        const emparejamientos = generarPlayoffsParaLiga(liga, clasificacion);

        if (!emparejamientos || emparejamientos.length === 0) continue;

        // Primera ronda: ida y vuelta
        const ida = emparejamientos.map(([local, visitante]) => ({
            local, visitante, jugado: false
        }));
        const vuelta = emparejamientos.map(([local, visitante]) => ({
            local: visitante, visitante: local, jugado: false
        }));

        rondas.push([...ida, ...vuelta]);

        // Liga 2 y Primera RFEF requieren final
        if (liga === "Liga 2" || liga.includes("Primera RFEF")) {
            // Segunda ronda (final) agregada más adelante en PlayoffMenu.js tras resultado
            rondas.push([]); // espacio reservado
        }

        // Tercera RFEF necesita 2 fases
        if (liga.includes("Tercera RFEF")) {
            rondas.push([]); // ronda final con 9 ascensos
        }
    }

    const estructuraPlayoffs = { rondas };
    localStorage.setItem("playoffs_actuales", JSON.stringify(estructuraPlayoffs));
    window.location.href = "/playoffs"; // redirección inmediata
}
